mapper.select:
SELECT * FROM note

    AND folder = #{folder}
    AND tags LIKE CONCAT('%', #{tag}, '%')
    AND priority = #{priority}
    AND is_favorite = #{isFavorite}
    AND is_encrypted = #{isEncrypted}
    AND is_archived = #{isArchived}
    AND is_deleted = #{isDeleted}
    AND (owner_id = #{ownerId} OR shared_with LIKE '%' || #{ownerId} || '%')

ORDER BY updated_at DESC

mapper.update:
UPDATE note SET is_archived = 0, is_deleted = 0, deleted_at = NULL,
    updated_at = datetime('now','localtime')
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) FROM note
WHERE priority = #{priority}
  AND created_at >= #{start} AND created_at <= #{end}
